var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 그쪽에도 없나?","JPN":"カスカベ、そこにもいないか？","ENG":"You don't see anything over there, Yuri?","TWN":"李悠麗，那裡也沒有嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"사람은커녕 시체도 안 보여.","JPN":"人どころか、死体すら無い。","ENG":"Nope. Not even a dead body.","TWN":"別說是活人，連個屍體都沒有。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"혹시 경찰이라도 다녀간 건 아닐까?","JPN":"もしかして警察が来てたとか？","ENG":"Maybe the cops have already been by?","TWN":"是不是員警來過了？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"경찰이 왔었으면 이 일대가 다 뒤집어졌을 거다.","JPN":"警察が来ていたなら、この一帯が大騒ぎになっているはずだ。","ENG":"The cops would have turned this entire neighborhood upside down.","TWN":"如果是員警，這一帶早就門庭若市了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"사방이 조용한 걸 보면 그건 아닐 것 같아.","JPN":"周りは静かだし、それはないだろう。","ENG":"It's too quiet for that.","TWN":"妳看周圍這麼安靜，員警應該沒來過。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼...... 지훈이랑 무기상 할아버지는?","JPN":"それじゃあ……ゴトウと武器屋のじいさんは？","ENG":"Then... what happened to Jihoon and the gunsmith?","TWN":"那麼……智勳和武器商爺爺呢？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"모르겠다. 살았는지, 죽었는지.","JPN":"知らない。生きているか、死んでいるかなんてな。","ENG":"I have no idea. Maybe they made it out. Maybe not.","TWN":"我也不知道是死是活。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그보다 우리에겐 시간이 없어. 도현이 놈 핸드폰은 찾았어?","JPN":"それより時間がない。リョウの携帯は見つけたか？","ENG":"But we don't have time to sit around and wonder about that. Have you found Dohyun's phone?","TWN":"我們沒時間管那麼多，找到道賢的手機了嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지금 지훈이보다 핸드폰이 더 중요해?","JPN":"ゴトウより携帯のほうが大事なの？","ENG":"Is that phone more important to you than Jihoon right now?","TWN":"手機比智勳的命更重要嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"내겐 중요해.","JPN":"俺にとっては大事だ。","ENG":"It is, to me.","TWN":"對我來說確實是。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"민병대에서 사람이 죽어나가는 건 흔한 일이지.","JPN":"民兵隊で人が死んでいくのはよくあることさ。","ENG":"People die all the time in the Militia.","TWN":"在民兵隊，隊員犧牲是常有的事。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 그 핸드폰 없이는 성냥팔이를 쫓을 수 없어.","JPN":"でも、あの携帯がないとマッチ売りを追跡できない。","ENG":"But we won't be able to track down the Matchmaker without the phone.","TWN":"但沒有那手機，我們就無法追蹤賣火柴組織。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"다들 왜 그렇게 매정한 거야?! 지훈이도 그렇고 대장까지!","JPN":"みんなどうしてそんなに薄情なんだ！？　ゴトウもそうだし、隊長まで！","ENG":"Why does everyone have to be so cold-hearted? First Jihoon, and now you...","TWN":"智勳也是，隊長也是！你們怎麼一個個都那麼無情！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지훈이에게 얼핏 들었어. 대장은 원래 경찰이었다면서?","JPN":"ゴトウから聞いたよ。隊長は元々警察官だったんだって？","ENG":"Jihoon sort of told me... that you used to be a cop.","TWN":"我聽智勳說過，隊長曾經當過員警是吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그리고 그 때의 부하들이 성냥팔이에게 당했다고, 그래서 복수하려는 거라고......","JPN":"昔の部下たちがマッチ売りにやられて、その復讐をするって……","ENG":"And you lost your men to the Matchmaker back then. That's why you want to take revenge...","TWN":"因為當時的部下被賣火柴組織殺害，所以才想要報仇……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"젠장! 취급이 달라도 너무 다르잖아!","JPN":"ちくしょう！　扱いが全然違うじゃん！","ENG":"Drat it! Don't you think it's unfair?","TWN":"該死！這待遇差的也太大了吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"순직한 경찰들은 소중한 동료들이고, 우린 그저 대장의 총알받이야?!","JPN":"殉職した警察官たちは大切な仲間で、私たちはただの弾除けか？","ENG":"You care so much about those cops who died in the line of duty, but we're just meat shields to you?","TWN":"殉職的員警是他的同伴，而我們只配當炮灰？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......미, 미안해. 방금 말은 잊어 줘.","JPN":"……ご、ごめん。今の話は忘れて。","ENG":"S-sorry. Forget what I just said.","TWN":"……對、對不起。別在意。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};